import React, { useState, useEffect } from 'react';
import { makeStyles } from '@material-ui/core/styles';
import Paper from '@material-ui/core/Paper';
import Tabs from '@material-ui/core/Tabs';
import Tab from '@material-ui/core/Tab';


const useStyles = makeStyles((theme) => ({
    root: {
        marginTop:'4.9rem',
        position: 'fixed',
        zIndex: 1,
        width:'100%',
    },
    colorPrimary: {
        color: '#fff',
        background: 'linear-gradient(#555, #222)',
        boxShadow: '0 1px 1px #777, 0 1px 0 #666 inset',
    },
}));

export default function MenuCrop(props) {
    console.log(props.crop)
    const [buff, setBuff] = useState(0)
    const classes = useStyles();
    const valueMenu = props.valueMenu;
    const setValueMenu = props.setValueMenu;
    
    useEffect(() => {
        if (props.crop !== buff) {
            const idx = props.crop;
            const section = (document.getElementById(`section${idx}`).offsetTop) - 120;
            window.scrollTo({
                top: section,
                behavior: "smooth"
            })
            setBuff(props.crop)
        }
    })
    
    const handleScroll = (e) => {
        const idx = parseInt(e.currentTarget.id.match(/(\d+\.\d+)|(\d+)/g));
        const section = (document.getElementById(`section${idx}`).offsetTop) - 120;
        window.scrollTo({
            top: section,
            behavior: "smooth"
        })
    }


    return (
        <Paper className={classes.root}>
            <div position="static" className={classes.colorPrimary}>
                <Tabs
                    value={valueMenu}
                    centered
                    selected={false}
                    variant="scrollable"
                    scrollButtons="auto"
                >
                    <Tab style={{ minWidth: 'auto', fontSize: '0.85rem' }} id="crop1" onClick={handleScroll} label="Ярі та озимі зернові культури" />
                    <Tab style={{ minWidth: 'auto', fontSize: '0.85rem' }} id="crop2" onClick={handleScroll} label="Соняшник" />
                    <Tab style={{ minWidth: 'auto', fontSize: '0.85rem' }} id="crop3" onClick={handleScroll} label="Кукурудза" />
                    <Tab style={{ minWidth: 'auto', fontSize: '0.85rem' }} id="crop4" onClick={handleScroll} label="Ярий та озимий ріпак" />
                    <Tab style={{ minWidth: 'auto', fontSize: '0.85rem' }} id="crop5" onClick={handleScroll} label="Соя" />
                    <Tab style={{ minWidth: 'auto', fontSize: '0.85rem' }} id="crop6" onClick={handleScroll} label="Цукровий буряк" />
                </Tabs>
            </div>
        </Paper>
    );
}