import Data from '../data/data.json';
const order = (content, complex, period, check, valueField) => {
    
    for (const prop in Data[1].drug) {
        complex.push([prop])
    }
    for (const prop in check) {
        if (check[prop]) { period.push(parseInt(prop.match(/\d+/))) }
    }

    for (let i = 0; i < content.length; i++) {
        const len = content[i]
        if (parseInt(len[len.length - 3].match(/\d+/)) !== valueField[len[0]]) {
            len[len.length - 3] = `${valueField[len[0]]}л.`
            len[len.length - 1] = `${(valueField[len[0]] * parseFloat(len[len.length - 2].match(/(\d+\.\d+)|(\d+)/g))).toFixed(2)}грн`
        }
        switch (content[i][0]) {
            case "Multicomplex Mo-Fe-Co":
                complex[0].push(len[len.length - 3])
                complex[0].push(len[len.length - 1])
                break;
            case "Multicomplex B":
                complex[1].push(len[len.length - 3])
                complex[1].push(len[len.length - 1])
                break;
            case "Multicomplex B-Сu":
                complex[2].push(len[len.length - 3])
                complex[2].push(len[len.length - 1])
                break;
            case "Multicomplex Zn":
                complex[3].push(len[len.length - 3])
                complex[3].push(len[len.length - 1])
                break;
            case "Multicomplex Mg":
                complex[4].push(len[len.length - 3])
                complex[4].push(len[len.length - 1])
                break;
            case "Multicomplex B-Mo":
                complex[5].push(len[len.length - 3])
                complex[5].push(len[len.length - 1])
                break;
            case "Multicomplex Mo-Co-Fe-Mn":
                complex[6].push(len[len.length - 3])
                complex[6].push(len[len.length - 1])
                break;
            case "Multicomplex Mn":
                complex[7].push(len[len.length - 3])
                complex[7].push(len[len.length - 1])
                break;
            default: break;
        }
    }
    return complex, period;
}
export default order;