import React from 'react';
import { makeStyles } from '@material-ui/core/styles';
import Toolbar from '@material-ui/core/Toolbar';
import IconButton from '@material-ui/core/IconButton';
import Menu from '@material-ui/core/Menu';
import MenuItem from '@material-ui/core/MenuItem';
import { Link } from 'react-router-dom';

import { ReactComponent as MenuIcon } from '../img/iconMenu.svg';

const useStyles = makeStyles((theme) => ({
    root: {
        flexGrow: 1,
        visibility: 'hidden',
        display:'none',
            [theme.breakpoints.down('md')]: {
                visibility: 'visible',
                display: 'block',
            },
    },
        colorPrimary: {
           // marginTop: '-3rem',
           // position: 'fixed',
           // background: 'linear-gradient(#555, #222)',
           // boxShadow: '0 1px 1px #777, 0 1px 0 #666 inset',
        },
    menuButton: {
        //marginRight: theme.spacing(2),
        padding:0,
    },
    title: {
        flexGrow: 1,
    },
}));

export default function MobileMenu() {
    const [anchorEl, setAnchorEl] = React.useState(null);
    const classes = useStyles();
    const handleClick = (event) => {
        setAnchorEl(event.currentTarget);
    };
    const handleClose = () => {
        setAnchorEl(null);
    };
    const handleScroll = (e) => {
        setAnchorEl(null);
        const idx = e.currentTarget.id;
            const section = (document.getElementById(`section${idx}`).offsetTop)-130;           
            window.scrollTo({
                top: section,
                behavior: "smooth"
            })
    }

    return (
        <div className={classes.root}>
            <div position="static" className={classes.colorPrimary}>
                <Toolbar className={classes.menuButton}>
                    <IconButton aria-controls="simple-menu" aria-haspopup="true" style={{ padding:'0px 0px 0px 8px'}} onClick={handleClick} edge="start"   aria-label="menu">
                        <MenuIcon />
                    </IconButton>
                    <Menu
                        id="simple-menu"
                        anchorEl={anchorEl}
                        keepMounted
                        open={Boolean(anchorEl)}
                        onClose={handleClose}
                    > 
                        <MenuItem component={Link} to='/' onClick={handleClose}>Про нас</MenuItem>
                        <MenuItem component={Link} to='/crop' onClick={handleClose}>Культури</MenuItem>
                        <MenuItem component={Link} to='/complex' onClick={handleClose}>Продукція</MenuItem>
                    </Menu>
                    
                   
                </Toolbar>
            </div>
        </div>
    );
}